declare module 'syslog-client' {
    import {EventEmitter} from 'events';

    export function createClient(target, options);

    export class Client extends EventEmitter {
        constructor(target:string, options);
        buildFormattedMessage(message, options):Buffer;
        close():Client;
        log(message, options, cb):Client;
        getTransport(cb);
        onClose():Client;
        onError(error):Client;
    }

    export enum Transport {
        Tcp = 1,
	Udp = 2
    }

    export enum Facility {
	Kernel = 0,
	User =   1,
	System = 3,
	Audit =  13,
	Alert =  14,
	Local0 = 16,
	Local1 = 17,
	Local2 = 18,
	Local3 = 19,
	Local4 = 20,
	Local5 = 21,
	Local6 = 22,
	Local7 = 23
    }
    
    export enum Severity {
	Emergency =     0,
	Alert =         1,
	Critical =      2,
	Error =         3,
	Warning =       4,
	Notice =        5,
	Informational = 6,
	Debug =         7
    }
}
